 <style>
 :root {
 --theme-color: #42b983;
 --sidebar-width: 250px;
 --content-max-width: 850px;
 --base-font-size: 13px;

 --code-border: rgba(0, 0, 0, 0.06);
 --code-toolbar-bg: #f6f8fa;
 --code-gutter-bg: #f6f8fa;
 --code-text: #24292f;
 --code-muted: #8b949e;
 }

 /* 侧边栏：简单的格式对齐修复 */
 .sidebar-nav ul li a {
 font-weight: normal !important;
 }
 .sidebar-nav a[href="#/"] + ul,
 .sidebar-nav a[href="#/README"] + ul {
 display: none !important;
 }
 .sidebar-nav a[href="#/"]::after,
 .sidebar-nav a[href="#/README"]::after {
 display: none !important;
 }

 /* 侧边栏：统一二级菜单项的格式对齐 */
 .sidebar-nav > ul > li > ul > li > a,
 .sidebar-nav > ul > li > ul > li:not(:has(a)) {
 font-size: inherit !important;
 line-height: inherit !important;
 padding-left: 20px !important;
 margin-left: 0 !important;
 font-weight: inherit !important;
 }

 /* ---------------- 代码块：统一顶栏 + 行级折叠（直接在代码块内） ---------------- */
 pre[data-lang] {
 position: relative !important;
 margin: 1.5em 0 !important;
 padding: 3.1em 0 0 !important; /* 顶部留工具栏 */
 border-radius: 12px !important;
 border: 1px solid rgba(0, 0, 0, 0.08) !important;
 background: #ffffff !important;
 overflow: hidden;
 box-shadow:
 0 1px 0 rgba(0, 0, 0, 0.02),
 0 12px 28px rgba(0, 0, 0, 0.06);
 transition: box-shadow 0.2s ease, transform 0.2s ease;
 }

 pre[data-lang]:hover {
 box-shadow:
 0 1px 0 rgba(0, 0, 0, 0.02),
 0 16px 34px rgba(0, 0, 0, 0.08);
 }

 pre[data-lang].is-collapsed {
 max-height: 44px !important;
 padding-bottom: 0 !important;
 cursor: pointer;
 }

 .code-tools {
 position: absolute;
 top: 0;
 left: 0;
 right: 0;
 height: 34px;
 padding: 0 12px;
 background: linear-gradient(180deg, rgba(246, 248, 250, 0.98), rgba(246, 248, 250, 0.92));
 border-bottom: 1px solid rgba(0, 0, 0, 0.06);
 display: flex;
 justify-content: space-between;
 align-items: center;
 z-index: 10;
 user-select: none;
 backdrop-filter: saturate(180%) blur(10px);
 -webkit-backdrop-filter: saturate(180%) blur(10px);
 }

 .code-tools-left {
 font-size: 11px;
 color: var(--code-muted);
 font-weight: 800;
 text-transform: uppercase;
 letter-spacing: 0.7px;
 display: flex;
 align-items: center;
 gap: 10px;
 }

 /* macOS 风格三色点 */
 .code-tools-left .dot {
 width: 8px;
 height: 8px;
 border-radius: 50%;
 display: inline-block;
 box-shadow: inset 0 0 0 1px rgba(0, 0, 0, 0.08);
 }

 .code-tools-left .dot:nth-of-type(1) { background: #ff5f57; }
 .code-tools-left .dot:nth-of-type(2) { background: #febc2e; }
 .code-tools-left .dot:nth-of-type(3) { background: #28c840; }

 .code-tools-right {
 display: flex;
 align-items: center;
 gap: 10px;
 }

 .tool-btn {
 font-size: 11px;
 color: var(--theme-color);
 cursor: pointer;
 font-weight: 700;
 padding: 4px 10px;
 border-radius: 999px;
 border: 1px solid rgba(66, 185, 131, 0.22);
 background: rgba(66, 185, 131, 0.08);
 transition: background 0.15s ease, border-color 0.15s ease, transform 0.15s ease;
 line-height: 1;
 }

 .tool-btn:hover {
 background: rgba(66, 185, 131, 0.14);
 border-color: rgba(66, 185, 131, 0.30);
 transform: translateY(-1px);
 }

 .tool-btn:active {
 transform: translateY(0);
 }

 /* 禁用 docsify-copy-code 的按钮（我们自己实现复制并放到顶栏） */
 .docsify-copy-code-button {
 display: none !important;
 }

 /* 行级折叠布局 */
 .fold-wrap {
 display: flex;
 background: #fff;
 }

 .fold-gutter {
 flex: 0 0 36px;
 background: transparent;
 border-right: 1px solid rgba(0, 0, 0, 0.04);
 user-select: none;
 padding: 10px 0;
 }

 .fold-gutter-row {
 height: 1.55em;
 display: flex;
 align-items: center;
 justify-content: flex-start;
 padding: 0 8px;
 gap: 8px;
 }

 .fold-toggle {
 width: 20px;
 height: 20px;
 display: inline-flex;
 align-items: center;
 justify-content: center;
 cursor: pointer;
 border-radius: 6px;
 transition: background 0.15s ease;
 flex: 0 0 20px;
 }

 .fold-toggle:hover {
 background: rgba(66, 185, 131, 0.10);
 }

 .fold-toggle svg {
 width: 14px;
 height: 14px;
 fill: #8b949e;
 transition: transform 0.15s ease, fill 0.15s ease;
 }

 .fold-toggle:hover svg {
 fill: var(--theme-color);
 }

 .fold-toggle.is-folded svg {
 transform: rotate(-90deg);
 }

 .fold-code-scroll {
 flex: 1;
 overflow-x: auto;
 padding: 10px 0;
 }

 pre[data-lang][data-inline-fold-skipped="1"] > code {
 display: block;
 padding: 10px 14px;
 overflow-x: auto;
 }

 /* ---------------- Tabs / Alerts / 图片缩放（产品级文档组件） ---------------- */
 /* Tabs（docsify-tabs） */
 .markdown-section .docsify-tabs {
 margin: 14px 0;
 border-radius: 12px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: #fff;
 overflow: hidden;
 box-shadow: 0 1px 0 rgba(0, 0, 0, 0.02);
 }

 .markdown-section .docsify-tabs__tab {
 font-size: 12px;
 font-weight: 800;
 letter-spacing: 0.4px;
 }

 .markdown-section .docsify-tabs__tab--active {
 color: var(--theme-color);
 }

 .markdown-section .docsify-tabs__content {
 padding: 10px 12px 2px;
 }

 /* Alerts（docsify-plugin-flexible-alerts） */
 .markdown-section .alert {
 margin: 14px 0;
 border-radius: 12px;
 border: 1px solid rgba(0, 0, 0, 0.10);
 background: #fff;
 box-shadow: 0 1px 0 rgba(0, 0, 0, 0.02);
 overflow: hidden;
 }

 .markdown-section .alert .title {
 font-size: 11px;
 font-weight: 900;
 letter-spacing: 0.6px;
 text-transform: uppercase;
 padding: 10px 12px;
 border-bottom: 1px solid rgba(0, 0, 0, 0.06);
 background: linear-gradient(180deg, rgba(246, 248, 250, 0.98), rgba(246, 248, 250, 0.92));
 }

 .markdown-section .alert p,
 .markdown-section .alert ul,
 .markdown-section .alert ol {
 margin: 10px 12px;
 }

 .markdown-section .alert.note,
 .markdown-section .alert.info {
 border-left: 4px solid #2f81f7;
 }

 .markdown-section .alert.tip,
 .markdown-section .alert.success {
 border-left: 4px solid var(--theme-color);
 }

 .markdown-section .alert.warning {
 border-left: 4px solid #d29922;
 }

 .markdown-section .alert.danger,
 .markdown-section .alert.error {
 border-left: 4px solid #cf222e;
 }

 /* 图片缩放（medium-zoom） */
 .medium-zoom-overlay {
 z-index: 1000;
 }

 .medium-zoom-image--opened {
 z-index: 1001;
 border-radius: 12px;
 box-shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
 }

 /* 让正文图片可点击（有些主题/样式会意外禁用 pointer-events） */
 .markdown-section img {
 pointer-events: auto !important;
 cursor: zoom-in !important;
 }

 .markdown-section a > img {
 cursor: zoom-in !important;
 }

 /* 关键：不要用 flex 渲染代码行，避免空白字符黏连导致"代码变形" */
 .fold-code-row {
 display: block;
 padding: 0 14px;
 white-space: pre;
 font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
 font-size: 13px;
 line-height: 1.55em;
 color: var(--code-text);
 }

 .fold-code-row.is-hidden {
 display: none;
 }

 .fold-ellipsis {
 display: none;
 margin-left: 10px;
 padding: 0 8px;
 border-radius: 999px;
 background: rgba(66, 185, 131, 0.10);
 color: var(--theme-color);
 font-size: 12px;
 cursor: pointer;
 user-select: none;
 }

 .fold-code-row.is-fold-head .fold-ellipsis {
 display: inline-block;
 }

 /* 在折叠状态，给起始行稍微高亮 */
 .fold-code-row.is-fold-head {
 background: rgba(66, 185, 131, 0.04);
 }

 /* 让 Prism token 样式还能生效（我们仍使用 Prism.highlight 输出 token span） */
 .fold-code-row .token.comment,
 .fold-code-row .token.prolog,
 .fold-code-row .token.doctype,
 .fold-code-row .token.cdata {
 color: #999;
 }

 /* ---------------- 评论区（giscus） ---------------- */
 .markdown-section #giscus {
 margin-top: 28px;
 }

 .markdown-section #giscus .giscus-card {
 border-radius: 12px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: #fff;
 overflow: hidden;
 box-shadow:
 0 1px 0 rgba(0, 0, 0, 0.02),
 0 12px 28px rgba(0, 0, 0, 0.06);
 }

 .markdown-section #giscus .giscus-head {
 display: flex;
 align-items: center;
 justify-content: space-between;
 padding: 10px 14px;
 background: linear-gradient(180deg, rgba(246, 248, 250, 0.98), rgba(246, 248, 250, 0.92));
 border-bottom: 1px solid rgba(0, 0, 0, 0.06);
 backdrop-filter: saturate(180%) blur(10px);
 -webkit-backdrop-filter: saturate(180%) blur(10px);
 }

 .markdown-section #giscus .giscus-head-left {
 display: flex;
 align-items: center;
 gap: 10px;
 }

 .markdown-section #giscus .giscus-title {
 font-size: 12px;
 font-weight: 800;
 letter-spacing: 0.6px;
 text-transform: uppercase;
 color: #1f2328;
 }

 .markdown-section #giscus .giscus-meta {
 font-size: 12px;
 color: var(--code-muted);
 }

 .markdown-section #giscus .giscus-badge {
 display: inline-flex;
 align-items: center;
 gap: 6px;
 padding: 4px 10px;
 border-radius: 999px;
 border: 1px solid rgba(66, 185, 131, 0.22);
 background: rgba(66, 185, 131, 0.08);
 color: var(--theme-color);
 font-size: 11px;
 font-weight: 700;
 line-height: 1;
 text-decoration: none;
 }

 .markdown-section #giscus .giscus-badge:hover {
 background: rgba(66, 185, 131, 0.14);
 border-color: rgba(66, 185, 131, 0.30);
 }

 .markdown-section #giscus .giscus-body {
 padding: 12px 14px 16px;
 }

 .markdown-section #giscus .giscus-body:empty {
 display: none;
 }

 .markdown-section .giscus-frame {
 width: 100%;
 }

 /* ---------------- 文章元信息（更新时间 / 阅读时长 / 字数） ---------------- */
 .page-meta-card {
 margin: 18px 0 18px;
 border-radius: 12px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: #fff;
 overflow: hidden;
 box-shadow:
 0 1px 0 rgba(0, 0, 0, 0.02),
 0 12px 28px rgba(0, 0, 0, 0.06);
 }

 .page-meta-head {
 display: flex;
 align-items: center;
 justify-content: space-between;
 padding: 10px 14px;
 background: linear-gradient(180deg, rgba(246, 248, 250, 0.98), rgba(246, 248, 250, 0.92));
 border-bottom: 1px solid rgba(0, 0, 0, 0.06);
 backdrop-filter: saturate(180%) blur(10px);
 -webkit-backdrop-filter: saturate(180%) blur(10px);
 }

 .page-meta-title {
 font-size: 12px;
 font-weight: 800;
 letter-spacing: 0.6px;
 text-transform: uppercase;
 color: #1f2328;
 }

 .page-meta-body {
 padding: 10px 14px;
 display: flex;
 flex-wrap: wrap;
 gap: 8px;
 align-items: center;
 color: #57606a;
 font-size: 13px;
 line-height: 1.6;
 }

 .page-meta-body b {
 color: #1f2328;
 font-weight: 800;
 }

 .page-meta-sep {
 opacity: 0.5;
 padding: 0 2px;
 }

 .page-tip {
 padding: 10px 14px;
 border-top: 1px dashed rgba(0, 0, 0, 0.10);
 background: rgba(66, 185, 131, 0.06);
 color: #1f2328;
 font-size: 13px;
 }

 .page-tip b {
 color: var(--theme-color);
 }

 /* ---------------- 右侧 TOC（目录增强） ---------------- */
 .toc-aside {
 position: fixed;
 top: 86px;
 right: 18px;
 width: 260px;
 max-height: calc(100vh - 110px);
 overflow: auto;
 border-radius: 12px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: #fff;
 box-shadow:
 0 1px 0 rgba(0, 0, 0, 0.02),
 0 12px 28px rgba(0, 0, 0, 0.06);
 z-index: 20;
 display: none;
 }

 /* 防止某次误判导致行内 display 卡死：用 data 属性控制是否真正显示 */
 .toc-aside[data-has-items="0"] {
 display: none !important;
 }

 .toc-head {
 position: sticky;
 top: 0;
 display: flex;
 align-items: center;
 justify-content: space-between;
 padding: 10px 12px;
 background: linear-gradient(180deg, rgba(246, 248, 250, 0.98), rgba(246, 248, 250, 0.92));
 border-bottom: 1px solid rgba(0, 0, 0, 0.06);
 backdrop-filter: saturate(180%) blur(10px);
 -webkit-backdrop-filter: saturate(180%) blur(10px);
 }

 .toc-title {
 font-size: 12px;
 font-weight: 800;
 letter-spacing: 0.6px;
 text-transform: uppercase;
 color: #1f2328;
 }

 .toc-actions {
 display: inline-flex;
 align-items: center;
 gap: 8px;
 }

 .toc-action {
 width: 30px;
 height: 30px;
 display: inline-flex;
 align-items: center;
 justify-content: center;
 border-radius: 12px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: rgba(255, 255, 255, 0.75);
 color: #57606a;
 cursor: pointer;
 line-height: 1;
 user-select: none;
 transition: transform 120ms ease, background 120ms ease, border-color 120ms ease, color 120ms ease, box-shadow 120ms ease;
 }

 .toc-icon {
 width: 16px;
 height: 16px;
 display: block;
 }

 .toc-action:hover {
 transform: translateY(-1px);
 background: rgba(66, 185, 131, 0.10);
 border-color: rgba(66, 185, 131, 0.26);
 color: #1f2328;
 box-shadow: 0 8px 16px rgba(0, 0, 0, 0.10);
 }

 .toc-action:active {
 transform: translateY(0);
 box-shadow: 0 6px 12px rgba(0, 0, 0, 0.08);
 }

 .toc-action.is-disabled {
 opacity: 0.42;
 filter: saturate(0.8);
 pointer-events: none;
 box-shadow: none;
 }

 .toc-action.is-hidden {
 display: none;
 }

 html[data-theme="dark"] .toc-action,
 html[data-theme="dark"] .toc-close {
 background: rgba(22, 27, 34, 0.72);
 border-color: rgba(255, 255, 255, 0.08);
 color: rgba(230, 237, 243, 0.78);
 }

 html[data-theme="dark"] .toc-action:hover,
 html[data-theme="dark"] .toc-close:hover {
 background: rgba(66, 185, 131, 0.10);
 border-color: rgba(66, 185, 131, 0.28);
 color: rgba(230, 237, 243, 0.92);
 }

 .toc-close {
 width: 28px;
 height: 28px;
 display: none;
 align-items: center;
 justify-content: center;
 border-radius: 10px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: rgba(255, 255, 255, 0.7);
 color: #57606a;
 cursor: pointer;
 font-size: 16px;
 line-height: 1;
 user-select: none;
 }

 .toc-close:hover {
 background: rgba(66, 185, 131, 0.10);
 border-color: rgba(66, 185, 131, 0.22);
 color: #1f2328;
 }

 .toc-fab {
 position: fixed;
 right: 14px;
 bottom: 16px;
 z-index: 9998;
 display: none;
 align-items: center;
 justify-content: center;
 padding: 10px 12px;
 border-radius: 999px;
 border: 1px solid rgba(66, 185, 131, 0.22);
 background: rgba(255, 255, 255, 0.92);
 color: #1f2328;
 font-size: 12px;
 font-weight: 900;
 letter-spacing: 0.6px;
 text-transform: uppercase;
 cursor: pointer;
 box-shadow: 0 10px 22px rgba(0, 0, 0, 0.10);
 backdrop-filter: saturate(180%) blur(10px);
 -webkit-backdrop-filter: saturate(180%) blur(10px);
 }

 .toc-body {
 padding: 10px 10px 12px;
 font-size: 12px;
 line-height: 1.55;
 color: #57606a;
 }

 .toc-body a {
 display: block;
 padding: 6px 8px;
 border-radius: 8px;
 color: inherit;
 text-decoration: none;
 border: 1px solid transparent;
 overflow: hidden;
 text-overflow: ellipsis;
 white-space: nowrap;
 }

 .toc-body a:hover {
 background: rgba(66, 185, 131, 0.08);
 border-color: rgba(66, 185, 131, 0.18);
 color: #1f2328;
 }

 .toc-body a.is-active {
 background: rgba(66, 185, 131, 0.12);
 border-color: rgba(66, 185, 131, 0.26);
 color: #1f2328;
 font-weight: 800;
 }

 /* TOC 目录树：h2 分组 + 子项折叠 */
 .toc-group {
 margin: 2px 0 6px;
 }

 .toc-group-head {
 display: flex;
 align-items: center;
 gap: 6px;
 }

 .toc-group-toggle {
 width: 22px;
 height: 22px;
 border-radius: 8px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: rgba(255, 255, 255, 0.6);
 color: inherit;
 cursor: pointer;
 display: inline-flex;
 align-items: center;
 justify-content: center;
 flex: 0 0 auto;
 }

 .toc-group-toggle.is-hidden {
 visibility: hidden;
 pointer-events: none;
 }

 .toc-caret {
 width: 14px;
 height: 14px;
 display: block;
 opacity: 0.8;
 transition: transform 120ms ease;
 }

 .toc-group.is-collapsed .toc-caret {
 transform: rotate(-90deg);
 }

 .toc-group-link {
 flex: 1;
 min-width: 0;
 }

 .toc-children {
 margin: 4px 0 0 11px;
 padding-left: 8px;
 border-left: 1px dashed rgba(0, 0, 0, 0.10);
 }

 .toc-group.is-collapsed .toc-children {
 display: none;
 }

 html[data-theme="dark"] .toc-group-toggle {
 background: rgba(22, 27, 34, 0.60);
 border-color: rgba(255, 255, 255, 0.10);
 }

 html[data-theme="dark"] .toc-children {
 border-left-color: rgba(255, 255, 255, 0.14);
 }

 .toc-l1 { padding-left: 0; font-weight: 900; }
 .toc-l2 { padding-left: 0; }
 .toc-l3 { padding-left: 12px; }
 .toc-l4 { padding-left: 22px; opacity: 0.95; }

 /* 只在大屏显示右侧 TOC：是否给正文预留空间由 body class 控制 */
 @media (min-width: 1024px) {
 .toc-aside { display: block; }
 body.has-toc-aside .content { padding-right: 300px; }
 }

 @media (max-width: 1023px) {
 .content { padding-right: 0; }

 /* 小屏：目录以浮层形式打开，默认隐藏，通过按钮唤起 */
 .toc-aside {
 display: none;
 left: 12px;
 right: 12px;
 top: 74px;
 width: auto;
 max-height: calc(100vh - 96px);
 z-index: 9999;
 }

 .toc-aside.is-open {
 display: block;
 }

 .toc-close {
 display: inline-flex;
 }

 .toc-fab {
 display: inline-flex;
 }

 body:not(.has-toc-aside) .toc-fab {
 opacity: 0.55;
 border-color: rgba(0, 0, 0, 0.10);
 color: #57606a;
 }

 body.has-toc-aside .toc-fab {
 opacity: 1;
 }
 }

 /* ---------------- 标题：复制链接（不污染 TOC 文本） ---------------- */
 .markdown-section h1,
 .markdown-section h2,
 .markdown-section h3,
 .markdown-section h4 {
 scroll-margin-top: 90px;
 }

 .heading-link-btn {
 display: inline-flex;
 align-items: center;
 justify-content: center;
 margin-left: 8px;
 width: 24px;
 height: 24px;
 border-radius: 8px;
 border: 1px solid rgba(66, 185, 131, 0.18);
 background: rgba(66, 185, 131, 0.08);
 color: var(--theme-color);
 cursor: pointer;
 user-select: none;
 -webkit-tap-highlight-color: transparent;
 vertical-align: middle;
 opacity: 0;
 transform: translateY(-1px);
 transition: opacity 0.15s ease, transform 0.15s ease, background 0.15s ease, border-color 0.15s ease;
 }

 .heading-link-btn:hover {
 background: rgba(66, 185, 131, 0.14);
 border-color: rgba(66, 185, 131, 0.30);
 transform: translateY(-1px);
 }

 .heading-link-btn.is-copied {
 background: rgba(66, 185, 131, 0.18);
 border-color: rgba(66, 185, 131, 0.38);
 }

 .markdown-section h1:hover .heading-link-btn,
 .markdown-section h2:hover .heading-link-btn,
 .markdown-section h3:hover .heading-link-btn,
 .markdown-section h4:hover .heading-link-btn {
 opacity: 1;
 }

 @media (hover: none) {
 .heading-link-btn {
 opacity: 0.85;
 }
 }

 html[data-theme="dark"] .heading-link-btn {
 border-color: rgba(102, 219, 162, 0.20);
 background: rgba(102, 219, 162, 0.10);
 color: rgba(102, 219, 162, 0.95);
 }

 html[data-theme="dark"] .heading-link-btn.is-copied {
 background: rgba(102, 219, 162, 0.18);
 border-color: rgba(102, 219, 162, 0.38);
 }

 /* ---------------- 阅读体验增强：进度条 / 面包屑 / 上一篇下一篇 ---------------- */
 #read-progress {
 position: fixed;
 top: 0;
 left: 0;
 height: 3px;
 width: 0;
 background: var(--theme-color);
 z-index: 999;
 transition: width 0.08s linear;
 }

 .page-breadcrumb {
 margin: 10px 0 12px;
 font-size: 12px;
 line-height: 1.5;
 color: var(--code-muted);
 display: flex;
 flex-wrap: wrap;
 align-items: center;
 gap: 6px;
 }

 .page-breadcrumb a {
 color: inherit;
 text-decoration: none;
 border-bottom: 1px dashed rgba(66, 185, 131, 0.25);
 }

 .page-breadcrumb a:hover {
 color: #1f2328;
 border-bottom-color: rgba(66, 185, 131, 0.55);
 }

 .page-breadcrumb .crumb-sep {
 opacity: 0.5;
 }

 .page-nav {
 margin: 18px 0 26px;
 display: grid;
 grid-template-columns: 1fr 1fr;
 gap: 12px;
 }

 .page-nav a {
 display: flex;
 flex-direction: column;
 gap: 4px;
 padding: 12px 14px;
 border-radius: 12px;
 border: 1px solid rgba(0, 0, 0, 0.08);
 background: #fff;
 box-shadow: 0 1px 0 rgba(0, 0, 0, 0.02);
 text-decoration: none;
 color: #1f2328;
 transition: transform 0.15s ease, box-shadow 0.15s ease, border-color 0.15s ease;
 }

 .page-nav a:hover {
 transform: translateY(-1px);
 box-shadow: 0 10px 24px rgba(0, 0, 0, 0.06);
 border-color: rgba(66, 185, 131, 0.25);
 }

 .page-nav .nav-kicker {
 font-size: 11px;
 font-weight: 800;
 letter-spacing: 0.6px;
 text-transform: uppercase;
 color: var(--code-muted);
 display: flex;
 align-items: center;
 gap: 6px;
 }

 .page-nav .nav-title {
 font-size: 13px;
 font-weight: 800;
 color: #1f2328;
 overflow: hidden;
 text-overflow: ellipsis;
 white-space: nowrap;
 }

 .page-nav .is-disabled {
 opacity: 0.45;
 pointer-events: none;
 }

 @media (max-width: 768px) {
 .page-nav {
 grid-template-columns: 1fr;
 }
 }

 /* 侧边栏样式 */
 .sidebar-nav > ul > li {
 margin: 10px 0;
 font-weight: bold;
 font-size: 14px;
 }

 /* ---------------- 主题切换按钮（暗色/亮色/跟随系统） ---------------- */
 .theme-toggle {
 position: fixed;
 right: 18px;
 bottom: 18px;
 z-index: 1002;
 display: inline-flex;
 align-items: center;
 gap: 8px;
 padding: 9px 12px;
 border-radius: 999px;
 border: 1px solid rgba(0, 0, 0, 0.10);
 background: rgba(255, 255, 255, 0.86);
 color: #111827;
 box-shadow: 0 10px 30px rgba(0, 0, 0, 0.10);
 cursor: pointer;
 user-select: none;
 -webkit-tap-highlight-color: transparent;
 backdrop-filter: saturate(180%) blur(12px);
 -webkit-backdrop-filter: saturate(180%) blur(12px);
 transition: transform 0.15s ease, box-shadow 0.15s ease, border-color 0.15s ease;
 font-size: 12px;
 font-weight: 800;
 letter-spacing: 0.6px;
 }

 .theme-toggle:hover {
 transform: translateY(-1px);
 box-shadow: 0 14px 38px rgba(0, 0, 0, 0.14);
 border-color: rgba(66, 185, 131, 0.28);
 }

 .theme-toggle:active {
 transform: translateY(0);
 }

 .theme-toggle .theme-icon {
 width: 18px;
 height: 18px;
 display: inline-flex;
 align-items: center;
 justify-content: center;
 border-radius: 6px;
 background: rgba(66, 185, 131, 0.10);
 color: var(--theme-color);
 font-size: 14px;
 line-height: 1;
 }

 .theme-toggle .theme-text {
 opacity: 0.9;
 }

 @media (max-width: 900px) {
 .theme-toggle {
 right: 12px;
 bottom: 12px;
 }
 }

 /* ---------------- 全文搜索（Ctrl/⌘+K） ---------------- */
 .search-toggle {
 position: fixed;
 right: 18px;
 bottom: 78px;
 z-index: 1002;
 display: inline-flex;
 align-items: center;
 gap: 8px;
 padding: 9px 12px;
 border-radius: 999px;
 border: 1px solid rgba(0, 0, 0, 0.10);
 background: rgba(255, 255, 255, 0.86);
 color: #111827;
 box-shadow: 0 10px 30px rgba(0, 0, 0, 0.10);
 cursor: pointer;
 user-select: none;
 -webkit-tap-highlight-color: transparent;
 backdrop-filter: saturate(180%) blur(12px);
 -webkit-backdrop-filter: saturate(180%) blur(12px);
 transition: transform 0.15s ease, box-shadow 0.15s ease, border-color 0.15s ease;
 font-size: 12px;
 font-weight: 800;
 letter-spacing: 0.6px;
 }

 .search-toggle:hover {
 transform: translateY(-1px);
 box-shadow: 0 14px 38px rgba(0, 0, 0, 0.14);
 border-color: rgba(66, 185, 131, 0.28);
 }

 .search-toggle:active {
 transform: translateY(0);
 }

 .search-toggle .search-icon {
 width: 18px;
 height: 18px;
 display: inline-flex;
 align-items: center;
 justify-content: center;
 border-radius: 6px;
 background: rgba(66, 185, 131, 0.10);
 color: var(--theme-color);
 }

 .search-toggle .search-icon svg {
 width: 16px;
 height: 16px;
 display: block;
 }

 .search-toggle .search-hint {
 opacity: 0.7;
 font-weight: 800;
 font-size: 11px;
 letter-spacing: 0.3px;
 }

 @media (max-width: 900px) {
 .search-toggle {
 right: 12px;
 bottom: 72px;
 }
 .search-toggle .search-hint {
 display: none;
 }
 }

 #fts-modal {
 position: fixed;
 inset: 0;
 z-index: 2000;
 display: none;
 }

 #fts-modal.is-open {
 display: block;
 }

 #fts-modal .fts-backdrop {
 position: absolute;
 inset: 0;
 background: rgba(15, 23, 42, 0.45);
 backdrop-filter: blur(10px);
 -webkit-backdrop-filter: blur(10px);
 }

 #fts-modal .fts-panel {
 position: relative;
 width: min(760px, calc(100vw - 24px));
 margin: 92px auto 0;
 border-radius: 14px;
 background: rgba(255, 255, 255, 0.95);
 border: 1px solid rgba(0, 0, 0, 0.10);
 box-shadow: 0 30px 90px rgba(0, 0, 0, 0.30);
 overflow: hidden;
 }

 #fts-modal .fts-head {
 padding: 12px 12px 10px;
 border-bottom: 1px solid rgba(0, 0, 0, 0.06);
 display: flex;
 gap: 10px;
 align-items: center;
 }

 #fts-modal .fts-input {
 flex: 1;
 height: 40px;
 border-radius: 10px;
 border: 1px solid rgba(0, 0, 0, 0.12);
 padding: 0 12px;
 outline: none;
 font-size: 14px;
 font-weight: 700;
 background: rgba(255, 255, 255, 0.9);
 }

 #fts-modal .fts-input:focus {
 border-color: rgba(66, 185, 131, 0.55);
 box-shadow: 0 0 0 3px rgba(66, 185, 131, 0.18);
 }

 #fts-modal .fts-close {
 width: 40px;
 height: 40px;
 border-radius: 10px;
 border: 1px solid rgba(0, 0, 0, 0.10);
 background: rgba(66, 185, 131, 0.08);
 color: var(--theme-color);
 cursor: pointer;
 font-weight: 900;
 font-size: 16px;
 }

