:root {
 /* 基础颜色 */
 --theme-color: #2563eb; /* 蓝色，更专业 */
 --text-color-base: #111827;
 --text-color-secondary: #4b5563;
 --bg-color-base: #ffffff;
 --bg-color-secondary: #f9fafb;
 --border-color: #e5e7eb;

