 /* 字体 */
 --base-font-family: "Inter", system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
 --code-font-family: "JetBrains Mono", "Fira Code", "Roboto Mono", monospace;
 --heading-font-family: var(--base-font-family);
}

/* 全局字体 */
body {
 font-family: var(--base-font-family) !important;
 color: var(--text-color-base);
 background-color: var(--bg-color-base);
 line-height: 1.7; /* 增加行高，提升阅读体验 */
 font-size: 16px; /* 稍微调大字号 */
}

/* 侧边栏样式 */
.sidebar {
 background-color: var(--sidebar-bg);
 border-right: var(--sidebar-border-right);
 width: var(--sidebar-width);
 padding-top: 20px;
}

.sidebar-nav ul {
 padding-left: 0;
}

.sidebar-nav li {
 margin: 6px 0;
}

.sidebar-nav a {
 color: var(--text-color-secondary);
 font-size: 14px;
 font-weight: 500;
 text-decoration: none;
 transition: color 0.2s;
}

.sidebar-nav a:hover {
 color: var(--theme-color);
}

.sidebar-nav .active > a {
 color: var(--theme-color);
 font-weight: 600;
 background: rgba(37, 99, 235, 0.05);
 border-radius: 6px;
}

/* 内容区域 */
.content {
 padding-top: 40px;
 max-width: var(--content-max-width);
 margin: 0 auto;
}

.markdown-section {
 max-width: 100%;
 padding: 0 40px 60px;
}

/* 标题样式 */
.markdown-section h1,
.markdown-section h2,
.markdown-section h3,
.markdown-section h4 {
 font-family: var(--heading-font-family);
 font-weight: 700;
 color: #111827;
