 color: #0f172a;
 }

 #fts-modal .fts-snippet {
 margin-top: 4px;
 font-size: 12px;
 line-height: 1.6;
 color: rgba(15, 23, 42, 0.78);
 }

 #fts-modal mark {
 background: rgba(250, 204, 21, 0.45);
 color: inherit;
 padding: 0 2px;
 border-radius: 4px;
 }

 /* 页面内高亮 */
 .fts-mark {
 background: rgba(250, 204, 21, 0.45);
 border-radius: 4px;
 padding: 0 2px;
 }

